<?php
namespace App\Services\Security;use App\Models\{SecurityIncident,SecurityPostmortemReviewCycle,User};use Carbon\Carbon;use Illuminate\Support\Collection;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class SecurityPostmortemReviewCycleService{public function scheduleReview(SecurityIncident $i,User $a,Carbon $due,string $reason):SecurityPostmortemReviewCycle{$c=SecurityPostmortemReviewCycle::create(['cycle_number'=>'SPR-'.now()->format('Ymd').'-'.Str::upper(Str::random(6)),'security_incident_id'=>$i->id,'status'=>'scheduled','review_reason'=>$reason,'due_at'=>$due,'scheduled_by_id'=>$a->id,'scheduled_at'=>now()]);$this->event($c,$a,'scheduled',$reason);return $c;}public function startReview(SecurityPostmortemReviewCycle $c,User $a):SecurityPostmortemReviewCycle{$c->update(['status'=>'in_review','reviewed_by_id'=>$a->id,'reviewed_at'=>now()]);$this->event($c,$a,'started','Postmortem follow-up review started.');return $c->refresh();}public function completeReview(SecurityPostmortemReviewCycle $c,User $a,string $summary):SecurityPostmortemReviewCycle{if(trim($summary)==='')throw ValidationException::withMessages(['summary'=>'Review summary is required.']);$c->update(['status'=>'completed','completed_by_id'=>$a->id,'completed_at'=>now(),'review_summary'=>$summary]);$this->event($c,$a,'completed',$summary);return $c->refresh();}public function cancelReview(SecurityPostmortemReviewCycle $c,User $a,string $reason):SecurityPostmortemReviewCycle{$c->update(['status'=>'cancelled']);$this->event($c,$a,'cancelled',$reason);return $c->refresh();}public function getOverdueReviews():Collection{return SecurityPostmortemReviewCycle::whereIn('status',['scheduled','in_review'])->where('due_at','<',now())->get();}public function getReviewReadiness():array{return ['overdue'=>$this->getOverdueReviews()->count(),'open'=>SecurityPostmortemReviewCycle::whereIn('status',['scheduled','in_review'])->count()];}private function event($c,$a,$t,$d){$c->events()->create(['security_incident_id'=>$c->security_incident_id,'actor_id'=>$a->id,'event_type'=>$t,'description'=>$d,'created_at'=>now()]);SecurityIncident::find($c->security_incident_id)->events()->create(['actor_id'=>$a->id,'event_type'=>"postmortem_review_{$t}",'description'=>$d,'created_at'=>now()]);}}
